# ========================================================================= # Имя файла: system-logon-init.ps1 # Назначение: Бескомпромиссная блокировка рекламы, телеметрии, Outlook и Яндекс.Музыки # Этап: System Logon / Pre-OOBE (Выполняется от имени SYSTEM) # Логирование: Документы дефолтного пользователя # =========================================================================
Set-StrictMode -Version Latest $ErrorActionPreference = 'Stop' $ProgressPreference = 'SilentlyContinue'
# Настройка логирования в C:\Users\Default\Documents $LogDir = "C:\Users\Default\Documents" if (-not (Test-Path $LogDir)) { New-Item -ItemType Directory -Force -Path $LogDir | Out-Null } Start-Transcript -Path (Join-Path $LogDir "System_Logon_Initialization.log") -Append
try { Write-Host "=========================================================" Write-Host " СТАРТ РАСШИРЕННОЙ ОПТИМИЗАЦИИ СИСТЕМЫ (SYSTEM CONTEXT)" Write-Host "========================================================="
# ---------------------------------------------------- # 1. ГЛОБАЛЬНЫЕ ПОЛИТИКИ (HKLM) ПРОТИВ РЕКЛАМЫ И МУСОРА # ---------------------------------------------------- Write-Host ">>> Настройка глобальных политик CloudContent..." $CloudContentPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\CloudContent" if (-not (Test-Path $CloudContentPath)) { New-Item -Path $CloudContentPath -Force | Out-Null } Set-ItemProperty -Path $CloudContentPath -Name "DisableWindowsConsumerFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path $CloudContentPath -Name "DisableWindowsSpotlightFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path $CloudContentPath -Name "DisableThirdPartySuggestions" -Value 1 -Type DWord -Force
Write-Host ">>> Глубокая конфигурация глобального ContentDeliveryManager..." $CdmPathHKLM = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\ContentDeliveryManager" if (-not (Test-Path $CdmPathHKLM)) { New-Item -Path $CdmPathHKLM -Force | Out-Null }
# Полный стек параметров блокировки фоновой тихой установки партнерского ПО $CdmTweaks = @{ "SilentInstalledAppsEnabled" = 0 "ContentDeliveryAllowed" = 0 "OemPreInstalledAppsEnabled" = 0 "PreInstalledAppsEnabled" = 0 "PreInstalledAppsReady" = 0 "SubscribedContentEnabled" = 0 "SystemPaneSuggestionsEnabled" = 0 "SubscribedContent-310093Enabled" = 0 "SubscribedContent-338387Enabled" = 0 "SubscribedContent-338388Enabled" = 0 "SubscribedContent-338389Enabled" = 0 "SubscribedContent-353475Enabled" = 0 } foreach ($Key in $CdmTweaks.Keys) { Set-ItemProperty -Path $CdmPathHKLM -Name $Key -Value $CdmTweaks[$Key] -Type DWord -Force }
# ---------------------------------------------------- # 2. ЖЕСТКИЙ АНТИДОТ ПРОТИВ ОБХОДА НОВОГО OUTLOOK (Фишка 2025/2026 гг.) # ---------------------------------------------------- Write-Host ">>> Аппаратное отключение OOBE-апдейтера для Outlook..." $USchedulerPath = "HKLM:\SOFTWARE\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe" if (-not (Test-Path $USchedulerPath)) { New-Item -Path $USchedulerPath -Force | Out-Null } # Записываем строковое значение-массив, блокирующее вызов апдейтера Set-ItemProperty -Path $USchedulerPath -Name "BlockedOobeUpdaters" -Value '["MS_Outlook"]' -Type String -Force
# Уничтожаем задание на форсированную установку, если оно уже создано обновлениями $OutlookUpdateTask = "HKLM:\SOFTWARE\Microsoft\WindowsUpdate\Orchestrator\UScheduler_Oobe\OutlookUpdate" if (Test-Path $OutlookUpdateTask) { Remove-Item -Path $OutlookUpdateTask -Recurse -Force }
# Запрещаем классическому Office предлагать переключение или скачивать новый Outlook $OutlookPolicyPath = "HKLM:\SOFTWARE\Policies\Microsoft\Office\16.0\Outlook\Options\General" if (-not (Test-Path $OutlookPolicyPath)) { New-Item -Path $OutlookPolicyPath -Force | Out-Null } Set-ItemProperty -Path $OutlookPolicyPath -Name "HideNewOutlookToggle" -Value 1 -Type DWord -Force
$OutlookPrefPath = "HKLM:\SOFTWARE\Policies\Microsoft\Office\16.0\Outlook\Preferences" if (-not (Test-Path $OutlookPrefPath)) { New-Item -Path $OutlookPrefPath -Force | Out-Null } Set-ItemProperty -Path $OutlookPrefPath -Name "NewOutlookMigrationUserSetting" -Value 0 -Type DWord -Force
# ---------------------------------------------------- # 3. НАСТРОЙКА ДЕФОЛТНОГО ПРОФИЛЯ ПОЛЬЗОВАТЕЛЯ (NTUSER.DAT) # ---------------------------------------------------- Write-Host ">>> Монтирование дефолтного куста реестра для настройки профилей..." $DefaultHivePath = "C:\Users\Default\NTUSER.DAT"
if (-not (Test-Path "HKLM:\TargetUser")) { reg load "HKLM\TargetUser" $DefaultHivePath | Out-Null }
$PathsToTweak = @( "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\ContentDeliveryManager", "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent" ) foreach ($Path in $PathsToTweak) { if (-not (Test-Path $Path)) { New-Item -Path $Path -Force | Out-Null } }
# Применяем весь спектр блокировок рекламы и автоустановок в дефолтный профиль будущего юзера Set-ItemProperty -Path "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent" -Name "DisableWindowsConsumerFeatures" -Value 1 -Type DWord -Force Set-ItemProperty -Path "HKLM:\TargetUser\Software\Policies\Microsoft\Windows\CloudContent" -Name "DisableWindowsSpotlightFeatures" -Value 1 -Type DWord -Force
foreach ($Key in $CdmTweaks.Keys) { Set-ItemProperty -Path "HKLM:\TargetUser\Software\Microsoft\Windows\CurrentVersion\ContentDeliveryManager" -Name $Key -Value $CdmTweaks[$Key] -Type DWord -Force }
# Безопасное штатное размонтирование куста обратно [GC]::Collect() [GC]::WaitForPendingFinalizers() reg unload "HKLM\TargetUser" | Out-Null Write-Host ">>> Профиль по умолчанию успешно защищен."
# ---------------------------------------------------- # 4. ОЧИСТКА БАЗ ДАННЫХ ПРЕДУСТАНОВКИ (PREINSTALLED PACKAGES) # ---------------------------------------------------- # Вырезаем записи из системного реестра предустановок, чтобы ликвидировать привязку к региону Write-Host ">>> Зачистка системной базы PreInstalledPackages..." $PreinstallPath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Appx\PreInstalledPackages" if (Test-Path $PreinstallPath) { Get-ChildItem -Path $PreinstallPath | Where-Object { $_.PSChildName -like "*Yandex*" -or $_.PSChildName -like "*Outlook*" } | ForEach-Object { Write-Host "Удаление ключа обязательной предустановки: $($_.PSChildName)" Remove-Item -Path $_.PSPath -Recurse -Force | Out-Null } }
# ---------------------------------------------------- # 5. ЧЕРНЫЙ СПИСОК УСТАНОВКИ (DEPROVISION) # ---------------------------------------------------- Write-Host ">>> Регистрация пакетов в черном списке депровизии..." $BlackList = @( "Microsoft.OutlookForWindows_8wekyb3d8bbwe", "A025C540.Yandex.Music_vfvw9svesycw6" ) foreach ($Family in $BlackList) { $DeprovisionPath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Appx\AppxAllUserStore\Deprovision\$Family" if (-not (Test-Path $DeprovisionPath)) { New-Item -Path $DeprovisionPath -Force | Out-Null } }
# ---------------------------------------------------- # 6. ЖЕСТКИЙ ПЕРЕХВАТ И УДАЛЕНИЕ ЖИВЫХ ИЛИ ЗАШИТЫХ В ИМИДЖ ПАКЕТОВ # ---------------------------------------------------- Write-Host ">>> Проверка и депровизия встроенных (Provisioned) пакетов в образе..." Get-AppxProvisionedPackage -Online | Where-Object { $_.DisplayName -match "OutlookForWindows|Yandex" } | ForEach-Object { Write-Host "Удаление зашитого пакета из системы: $($_.DisplayName)" Remove-AppxProvisionedPackage -Online -PackageName $_.PackageName -ErrorAction SilentlyContinue | Out-Null }
Write-Host ">>> Принудительное удаление из текущей сессии SYSTEM (если успели подгрузиться)..." Get-AppxPackage -AllUsers | Where-Object { $_.Name -match "OutlookForWindows|Yandex" } | Remove-AppxPackage -AllUsers -ErrorAction SilentlyContinue
Write-Host ">>> Все превентивные и блокирующие меры успешно применены!"
} catch { Write-Warning "Критический сбой в логон-скрипте: $($_.Exception.Message)"
# Защита системы от блокировки дефолтного профиля при ошибке if (Test-Path "HKLM:\TargetUser") { try { Write-Host ">>> Экстренное освобождение ресурсов и размонтирование куста реестра..." [GC]::Collect() [GC]::WaitForPendingFinalizers() reg unload "HKLM\TargetUser" 2>&1 | Out-Null } catch { # Подавляем вложенные ошибки } } throw $_ } finally { Stop-Transcript }

# =========================================================================
# Назначение: Автономный загрузчик с авто-исправлением кодировки и переносов
# Папка назначения: C:\Windows\Setup\Scripts
# =========================================================================

[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

$targetDir = 'C:\Windows\Setup\Scripts'
if (!(Test-Path $targetDir)) { 
    New-Item $targetDir -ItemType Directory -Force | Out-Null 
}

$LogFile = Join-Path $targetDir "Download_Bootstrapper.log"
Start-Transcript -Path $LogFile -Append -Force

try {
    Write-Host "========================================================="
    Write-Host " СТАРТ МОДУЛЯ ЗАГРУЗКИ С АВТО-ЛЕЧЕНИЕМ СКРИПТОВ"
    Write-Host "========================================================="

    # ОБНОВЛЕННЫЕ ПУТИ К РЕПОЗИТОРИЮ
    $baseUrl = 'https://raw.githubusercontent.com/AgentSharik/powershell-scripts/main/Scripts/'
    $fileList = @('manager.ps1', 'apps-install.ps1', 'clean-and-photo.ps1', 'install-sys-components.ps1', 'office-install.ps1', 'reset-setup-scripts.ps1')

    # Попытка получить свежий список файлов через API GitHub
    try {
        $apiUrl = 'https://api.github.com/repos/AgentSharik/powershell-scripts/contents/Scripts'
        $apiResponse = Invoke-RestMethod -Uri $apiUrl -UseBasicParsing -ErrorAction Stop
        if ($apiResponse) {
            $fileList = $apiResponse | Where-Object { $_.type -eq 'file' } | Select-Object -ExpandProperty name
        }
    } catch {
        Write-Warning "-> GitHub API недоступен. Используем резервный список файлов."
    }

    Write-Host "`n[1/2] Скачивание и исправление синтаксиса..."
    foreach ($fileName in $fileList) {
        $outPath = Join-Path $targetDir $fileName
        $url = $baseUrl + $fileName
        
        Write-Host "Обработка: $fileName ... " -NoNewline
        try {
            # 1. Скачиваем файл как чистую UTF-8 строку в память
            $webClient = New-Object System.Net.WebClient
            $webClient.Encoding = [System.Text.Encoding]::UTF8
            $rawContent = $webClient.DownloadString($url)
            
            # 2. ИСПРАВЛЕНИЕ 1: Лечим текстовые '\r\n', превращая их в системные маркеры строк
            if ($rawContent -match '\\r\\n') {
                $rawContent = $rawContent -replace '\\r\\n', "`r`n"
            }
            
            # 3. ИСПРАВЛЕНИЕ 2: Принудительно сохраняем файл на диск в UTF-8 с сигнатурой BOM.
            # Это полностью убирает кракозябры и защищает кириллицу в PowerShell 5.1
            [System.IO.File]::WriteAllText($outPath, $rawContent, [System.Text.Encoding]::UTF8)
            
            Write-Host "УСПЕШНО ИСПРАВЛЕН" -ForegroundColor Green
        } catch {
            Write-Host "ОШИБКА" -ForegroundColor Red
            Write-Warning "Не удалось обработать файл $fileName : $($_.Exception.Message)"
        }
    }

    $managerPath = Join-Path $targetDir 'manager.ps1'
    if (Test-Path $managerPath) {
        Write-Host "`n[2/2] Все файлы вылечены. Запуск Диспетчера в новом окне..." -ForegroundColor Green
        Stop-Transcript
        
        # Запуск менеджера в отдельном чистом интерактивном окне
        Start-Process powershell.exe -ArgumentList "-NoProfile -ExecutionPolicy Bypass -NoExit -File `"$managerPath`"" -WindowStyle Normal
    } else {
        Write-Error "Критический сбой: Файл manager.ps1 отсутствует!"
        Stop-Transcript
    }
} catch {
    Write-Error "Глобальная ошибка: $($_.Exception.Message)"
    try { Stop-Transcript } catch {}
}

